// ── NM-derived freight curves (scale from base × nm/nm_base) ─────────────────
(function(){
  function nmScale(base,factor){return CP_SEED_FR[base].map(v=>v!=null?+(v*factor).toFixed(3):null);}
  Object.assign(CP_SEED_FR,{
    // Iberia (Huelva NM from DB)
    sabine_iberia:      nmScale('sabine_rotterdam',  4670/5030),
    trinidad_iberia:    nmScale('trinidad_gate',     3383/4044),
    angola_iberia:      nmScale('angola_gate',       3935/5008),
    nigeria_iberia:     nmScale('nigeria_gate',      3359/4432),
    qatar_iberia:       nmScale('qatar_gate',        13000/13600),
    oman_iberia:        nmScale('oman_gate',         11500/12100),
    // Revithoussa/Italy — via Gibraltar route
    trinidad_rev:       nmScale('trinidad_gate',     5400/4044),
    angola_rev:         nmScale('angola_gate',       6100/5008),
    nigeria_rev:        nmScale('nigeria_gate',      5600/4432),
    qatar_rev:          nmScale('qatar_gate',        14365/13600),
    oman_rev:           nmScale('oman_gate',         12900/12100),
    // Swinoujscie — gate + 670 NM Baltic extension
    trinidad_swinoujscie: nmScale('trinidad_gate',   4714/4044),
    angola_swinoujscie:   nmScale('angola_gate',     5678/5008),
    nigeria_swinoujscie:  nmScale('nigeria_gate',    5102/4432),
    // Maptaphut — tokyo minus 2046 NM (constant delta)
    sabine_maptaphut:   nmScale('sabine_tokyo',      14254/16300),
    trinidad_maptaphut: nmScale('trinidad_tokyo',    12554/14600),
    // South America — Sabine → Guanabara 5359 NM, Sabine → Escobar 6497 NM
    sabine_guanabara:   nmScale('sabine_rotterdam',  5359/5030),
    sabine_escobar:     nmScale('sabine_rotterdam',  6497/5030),
  });
})();

const CP_TABS=['PHYS DIFFERENTIALS','DES PRICES','GLOBAL ARB','ATLANTIC BASIN','MEI','PACIFIC BASIN','FR DIFF vs BASIS'];
let CP={fp:null,phys:null,freight:null,liqFee:null,histSnaps:null,tab:0,selMonth:0,indexMode:'TTF',hhSlope:1.15,coghMode:false,histSnapDate:new Date().toISOString().slice(0,10)};
function cpGet(k,d){try{const v=localStorage.getItem(k);return v?JSON.parse(v):d;}catch{return d;}}
function cpSet(k,v){try{localStorage.setItem(k,JSON.stringify(v));}catch{}}
function fv(v,d=3){return v!=null&&!isNaN(v)?v.toFixed(d):'-';}
function fvi(v,d=3){return v!=null&&!isNaN(v)?v.toFixed(d):'0.000';}
function posCol(v){return v>0.05?'#4caf50':v<-0.05?'#ef4444':'#c8d6e5';}

function cpDerived(){
  const{fp,phys}=CP;
  const sl=CP.hhSlope||1.15;
  // ── Bulletproof freight: per-element fallback to seed, every render ─────────
  const _cfr=CP.freight||{};
  const freight={};
  Object.keys(CP_SEED_FR).forEach(k=>{
    const src=_cfr[k];const sd=CP_SEED_FR[k];
    if(Array.isArray(src)&&src.some(v=>v!=null&&!isNaN(v)))
      freight[k]=src.map((v,i)=>(v!=null&&!isNaN(v))?v:sd[i]);
    else freight[k]=sd.slice();
  });
  CP.freight=freight; // write back so basin tabs (cpGlobalArb/Atlantic/MEI/Pacific) get clean values
  // ── Physical diffs ─────────────────────────────────────────────────────────
  const phyItaly=ML.map((_,i)=>phys.nwe[i]+(freight.sabine_rovigo?.[i]??freight.sabine_rotterdam[i]*1.21)-(freight.sabine_rotterdam[i]));
  // Thailand diff: Angola Dahej - Angola MapTaPhut (via COGH)
  const phyThailand=ML.map((_,i)=>{const amt=freight.angola_maptaphut?.[i]??freight.angola_dahej[i]*1.233;return +(freight.angola_dahej[i]-amt).toFixed(3);});
  const ov=cpGet('cp_phys_ov',{});
  const termFr=(t,i)=>phys.nwe[i]+((freight['sabine_'+t]?.[i]??0)-(freight.sabine_rotterdam[i]));
  const withOv=(t,base,i)=>{const k=t+'_'+i;return ov[k]!=null?ov[k]:base;};
  const phyMei    =ML.map((_,i)=>withOv('mei',    +(freight.angola_dahej[i]-freight.angola_tokyo[i]).toFixed(3),i));
  const phyKlaipeda=ML.map((_,i)=>withOv('klaipeda',termFr('klaipeda',i),i));
  const phyInkoo   =ML.map((_,i)=>withOv('inkoo',   termFr('inkoo',i),   i));
  const phyRev     =ML.map((_,i)=>withOv('rev',     termFr('rev',i),     i));
  const phyKrk     =ML.map((_,i)=>withOv('krk',     termFr('krk',i),     i));
  const phyAin     =ML.map((_,i)=>withOv('ain',     termFr('ain',i)+(CP.egyptPremium??0.50),i));
  const phyAli     =ML.map((_,i)=>withOv('ali',     termFr('ali',i),     i)); // no premium — Turkish terminal
  const phySwino   =ML.map((_,i)=>withOv('swino',   termFr('swinoujscie',i)+0.02,i)); // +$0.02: ice/pilotage premium
  // ── South America (Brazil + Argentina) — FOB-netback from USGC ──────────────
  // For each month: compute FOB netback (vs TTF) from Sabine Pass across all known
  // TTF-linked destinations, take the best, then add the Sabine→destination freight.
  // Formula: phyDest = best_USGC_netback_vs_TTF + freight.sabine_<dest>
  // Fallback if sabine_guanabara / sabine_escobar absent in CP.freight: use angola_dahej
  // ratio as coarse proxy. User can always override per cell.
  function _usgcBestNetbackVsTtf(i){
    const cands = [
      phys.nwe[i]       - (freight.sabine_rotterdam?.[i]      ?? 0),
      phys.iberia[i]    - (freight.sabine_iberia?.[i]         ?? freight.sabine_rotterdam?.[i] ?? 0),
      phyItaly[i]       - (freight.sabine_rovigo?.[i]         ?? freight.sabine_rotterdam?.[i] * 1.10 ?? 0),
      phyRev[i]         - (freight.sabine_rev?.[i]            ?? freight.sabine_rotterdam?.[i] * 1.15 ?? 0),
      phyKrk[i]         - (freight.sabine_krk?.[i]            ?? freight.sabine_rotterdam?.[i] * 1.14 ?? 0),
      phyAin[i]         - (freight.sabine_ain?.[i]            ?? freight.sabine_rotterdam?.[i] * 1.34 ?? 0),
      phyAli[i]         - (freight.sabine_ali?.[i]            ?? freight.sabine_rotterdam?.[i] * 1.28 ?? 0),
      phyKlaipeda[i]    - (freight.sabine_klaipeda?.[i]       ?? freight.sabine_rotterdam?.[i] * 1.17 ?? 0),
      phyInkoo[i]       - (freight.sabine_inkoo?.[i]          ?? freight.sabine_rotterdam?.[i] * 1.21 ?? 0),
      phySwino[i]       - (freight.sabine_swinoujscie?.[i]    ?? freight.sabine_rotterdam?.[i] * 1.13 ?? 0),
    ].filter(v => v != null && !isNaN(v));
    return cands.length ? Math.max.apply(null, cands) : null;
  }
  const phyBrazil = ML.map((_,i) => {
    const nb = _usgcBestNetbackVsTtf(i);
    const fr = freight.sabine_guanabara?.[i];
    if(nb == null || fr == null) return withOv('brazil', null, i);
    return withOv('brazil', +(nb + fr).toFixed(3), i);
  });
  const phyArgentina = ML.map((_,i) => {
    const nb = _usgcBestNetbackVsTtf(i);
    const fr = freight.sabine_escobar?.[i];
    if(nb == null || fr == null) return withOv('argentina', null, i);
    return withOv('argentina', +(nb + fr).toFixed(3), i);
  });
  // ── DES absolute prices ────────────────────────────────────────────────────
  const des={
    nwe:     ML.map((_,i)=>fp.TTF[i]+phys.nwe[i]),
    iberia:  ML.map((_,i)=>fp.TTF[i]+phys.iberia[i]),
    uk:      ML.map((_,i)=>fp.TTF[i]+phys.uk[i]),
    italy:   ML.map((_,i)=>fp.TTF[i]+phyItaly[i]),
    klaipeda:ML.map((_,i)=>fp.TTF[i]+phyKlaipeda[i]),
    inkoo:   ML.map((_,i)=>fp.TTF[i]+phyInkoo[i]),
    rev:     ML.map((_,i)=>fp.TTF[i]+phyRev[i]),
    krk:     ML.map((_,i)=>fp.TTF[i]+phyKrk[i]),
    ain:     ML.map((_,i)=>fp.TTF[i]+phyAin[i]),
    ali:     ML.map((_,i)=>fp.TTF[i]+phyAli[i]),
    swino:   ML.map((_,i)=>fp.TTF[i]+phySwino[i]),
    mei:     ML.map((_,i)=>fp.JKM[i]+phyMei[i]),
    jktc:    ML.map((_,i)=>fp.JKM[i]+phys.jktc[i]),
    thailand:ML.map((_,i)=>{const ov2=cpGet('cp_phys_ov',{});const base=fp.JKM[i]+(ov2['thailand_'+i]!=null?ov2['thailand_'+i]:phyThailand[i]);return base;}),
    brazil:  ML.map((_,i)=>phyBrazil[i]!=null?fp.TTF[i]+phyBrazil[i]:null),
    argentina:ML.map((_,i)=>phyArgentina[i]!=null?fp.TTF[i]+phyArgentina[i]:null),
  };
  // ── USGC FOB cost ──────────────────────────────────────────────────────────
  const usgcFob=ML.map((_,i)=>sl*fp.HH[i]+(CP.liqFee[i]||0));
  // ── FOB Netback expressed as index equivalent ──────────────────────────────
  // formula: DES_price - freight - index_flat → spread over index
  // For USGC (HH-linked): DES - freight - sl*HH
  function nb(desArr,frArr,idxArr){return ML.map((_,i)=>desArr[i]-frArr[i]-idxArr[i]);}
  const slHH=ML.map((_,i)=>sl*fp.HH[i]);
  // Atlantic: Sabine (cost base = sl*HH)
  const sabNbNwe  =nb(des.nwe,  freight.sabine_rotterdam,slHH);
  const sabNbJktc =nb(des.jktc, freight.sabine_tokyo,    slHH);
  const sabNbMei  =nb(des.mei,  freight.sabine_dahej||freight.sabine_tokyo,slHH);
  const sabNbAin  =nb(des.ain,  freight.sabine_ain,      slHH);
  // Atlantic: Trinidad (cost base = TTF)
  const triNbNwe  =nb(des.nwe,  freight.trinidad_gate,  fp.TTF);
  const triNbJktc =nb(des.jktc, freight.trinidad_tokyo, fp.JKM);
  const triNbMei  =nb(des.mei,  freight.trinidad_dahej, fp.JKM);
  const triNbAin  =nb(des.ain,  freight.trinidad_ain,   fp.TTF);
  // Atlantic: Angola
  const angNbNwe  =nb(des.nwe,  freight.angola_gate,    fp.TTF);
  const angNbJktc =nb(des.jktc, freight.angola_tokyo,   fp.JKM);
  const angNbMei  =nb(des.mei,  freight.angola_dahej,   fp.JKM);
  const angNbAin  =nb(des.ain,  freight.angola_ain,     fp.TTF);
  // Atlantic: Nigeria
  const nigNbNwe  =nb(des.nwe,  freight.nigeria_gate,   fp.TTF);
  const nigNbJktc =nb(des.jktc, freight.nigeria_tokyo,  fp.JKM);
  const nigNbMei  =nb(des.mei,  freight.nigeria_dahej,  fp.JKM);
  const nigNbAin  =nb(des.ain,  freight.nigeria_ain,    fp.TTF);
  // MEI: Qatar
  const qatNbEur  =nb(des.nwe,  freight.qatar_gate,     fp.TTF);
  const qatNbAsia =nb(des.jktc, freight.qatar_tokyo,    fp.JKM);
  const qatNbMei  =nb(des.mei,  freight.qatar_dahej,    fp.JKM);
  const qatNbAin  =nb(des.ain,  freight.qatar_ain,      fp.TTF);
  // MEI: Oman
  const omnNbEur  =nb(des.nwe,  freight.oman_gate,      fp.TTF);
  const omnNbAsia =nb(des.jktc, freight.oman_tokyo,     fp.JKM);
  const omnNbMei  =nb(des.mei,  freight.oman_dahej,     fp.JKM);
  const omnNbAin  =nb(des.ain,  freight.oman_ain,       fp.TTF);
  // Pacific: Australia Barrow
  const abNbAsia  =nb(des.jktc, freight.australia_b_tokyo, fp.JKM);
  const abNbAin   =nb(des.ain,  freight.australia_b_ain,   fp.JKM);
  // Pacific: Australia Gladstone
  const agNbAsia  =nb(des.jktc, freight.australia_g_tokyo, fp.JKM);
  const agNbAin   =nb(des.ain,  freight.australia_g_ain,   fp.JKM);
  // Pacific: Indonesia
  const idxNbAsia =nb(des.jktc, freight.indonesia_tokyo,   fp.JKM);
  const idxNbAin  =nb(des.ain,  freight.indonesia_ain,     fp.JKM);
  // ── Sabine / Trinidad Panama Canal variants (Asia routes only) ────────────
  // PC NM (from Excel audit): sabine→tokyo 9264, trinidad→tokyo 8901.
  // CoGH NM (current NM table, preserved):  sabine→tokyo 15379, trinidad→tokyo 13231.
  // Scale CoGH freight by NM ratio (≈ linear approximation) then add canal fee.
  // PC_CANAL_FEE_PER_MMBTU = $1,000,000 per transit / 3,800,000 MMBtu cargo ≈ $0.263.
  const PC_CANAL_FEE_PER_MMBTU = 1000000 / 3800000;
  const sabine_tokyo_pc = ML.map((_,i)=>freight.sabine_tokyo?.[i]!=null?+(freight.sabine_tokyo[i]*(9264/15379)+PC_CANAL_FEE_PER_MMBTU).toFixed(3):null);
  const trinidad_tokyo_pc = ML.map((_,i)=>freight.trinidad_tokyo?.[i]!=null?+(freight.trinidad_tokyo[i]*(8901/13231)+PC_CANAL_FEE_PER_MMBTU).toFixed(3):null);
  // Netbacks for the PC-routed variants (Asia only)
  const sabNbJktcPc = nb(des.jktc, sabine_tokyo_pc, fp.JKM);
  const triNbJktcPc = nb(des.jktc, trinidad_tokyo_pc, fp.JKM);
  // ── Swing signal ──────────────────────────────────────────────────────────
  const jkmTtf    =ML.map((_,i)=>CP.fp.SP_JT?.[i]!=null?CP.fp.SP_JT[i]:+(fp.JKM[i]-fp.TTF[i]).toFixed(3));
  const frDiff    =ML.map((_,i)=>freight.sabine_tokyo[i]-freight.sabine_rotterdam[i]);// Asia extra cost
  const arbOpen   =ML.map((_,i)=>jkmTtf[i]>frDiff[i]);// Asia arb open when spread > extra freight
  const profEur   =sabNbNwe;
  const profAsia  =sabNbJktc;
  return{des,freight,phyItaly,phyKlaipeda,phyInkoo,phyRev,phyKrk,phyAin,phyAli,phySwino,phyMei,phyThailand,phyBrazil,phyArgentina,usgcFob,
    sabNbNwe,sabNbJktc,sabNbMei,sabNbAin,
    triNbNwe,triNbJktc,triNbMei,triNbAin,
    angNbNwe,angNbJktc,angNbMei,angNbAin,
    nigNbNwe,nigNbJktc,nigNbMei,nigNbAin,
    qatNbEur,qatNbAsia,qatNbMei,qatNbAin,
    omnNbEur,omnNbAsia,omnNbMei,omnNbAin,
    abNbAsia,abNbAin,agNbAsia,agNbAin,idxNbAsia,idxNbAin,
    sabine_tokyo_pc,trinidad_tokyo_pc,sabNbJktcPc,triNbJktcPc,
    jkmTtf,frDiff,arbOpen,profEur,profAsia};
}
// ── Freight seed version: bump whenever seed curves change to force cache refresh ──
const CP_FREIGHT_VER='v57_qatar_oman_cogh_apr2026';

function cpMergeFreight(){
  // Additive merge only — never auto-wipes user edits.
  // User controls refresh explicitly via "FREIGHT SEED" button (see cpFreightApplySeed).
  // Seed provides baseline + fills gaps; cached user values win where present.
  const seed=JSON.parse(JSON.stringify(CP_SEED_FR));
  const cached=cpGet('cp_freight',{});
  const merged=Object.assign({},seed);
  if(cached&&typeof cached==='object'){
    Object.entries(cached).forEach(([k,v])=>{
      if(!Array.isArray(v)||!v.some(x=>x!=null&&!isNaN(x)))return;
      const sd=seed[k];
      // Per-cell: cached wins when valid, seed fills holes
      merged[k]=v.map((x,i)=>(x!=null&&!isNaN(x))?x:(sd?sd[i]:null));
    });
  }
  return merged;
}
// ── Per-section seed diff & apply helpers ──────────────────────────────────
// Used by the "confirm-or-refresh" buttons in the Foundation header.
// Each returns {hasDiff, newKeys, changedKeys, cellDiffs} vs localStorage cache.
const _EPS=0.001;
function _arrDiff(seedArr,cachedArr){
  if(!Array.isArray(seedArr))return 0;
  if(!Array.isArray(cachedArr))return seedArr.length;
  let n=0;seedArr.forEach((s,i)=>{const c=cachedArr[i];
    if(s==null&&c==null)return;
    if(c==null||isNaN(c)||s==null||isNaN(s))n++;
    else if(Math.abs(c-s)>_EPS)n++;
  });return n;
}
function cpFreightSeedDiff(){
  const seed=CP_SEED_FR,cached=cpGet('cp_freight',{})||{};
  const newKeys=[],changedKeys=[];let cellDiffs=0;
  Object.keys(seed).forEach(k=>{
    const c=cached[k];
    if(!Array.isArray(c)||!c.some(v=>v!=null&&!isNaN(v))){newKeys.push(k);cellDiffs+=seed[k].length;return;}
    const n=_arrDiff(seed[k],c);if(n>0){changedKeys.push(k);cellDiffs+=n;}
  });
  return{hasDiff:newKeys.length>0||changedKeys.length>0,newKeys,changedKeys,cellDiffs};
}
function cpPhysSeedDiff(){
  const seed=CP_SEED_PHYS,cached=cpGet('cp_phys',{})||{};
  const newKeys=[],changedKeys=[];let cellDiffs=0;
  Object.keys(seed).forEach(k=>{
    const c=cached[k];
    if(!Array.isArray(c)||!c.some(v=>v!=null&&!isNaN(v))){newKeys.push(k);cellDiffs+=seed[k].length;return;}
    const n=_arrDiff(seed[k],c);if(n>0){changedKeys.push(k);cellDiffs+=n;}
  });
  return{hasDiff:newKeys.length>0||changedKeys.length>0,newKeys,changedKeys,cellDiffs};
}
function cpPricesSeedDiff(){
  const seed=CP_SEED_PRICES,cached=cpGet('cp_fp',{})||{};
  const newKeys=[],changedKeys=[];let cellDiffs=0;
  Object.keys(seed).forEach(k=>{
    const c=cached[k];
    if(!Array.isArray(c)||!c.some(v=>v!=null&&!isNaN(v))){newKeys.push(k);cellDiffs+=seed[k].length;return;}
    const n=_arrDiff(seed[k],c);if(n>0){changedKeys.push(k);cellDiffs+=n;}
  });
  return{hasDiff:newKeys.length>0||changedKeys.length>0,newKeys,changedKeys,cellDiffs};
}
function cpFreightApplySeed(){
  const d=cpFreightSeedDiff();
  if(!d.hasDiff){alert('✓ Freight already matches seed ('+CP_FREIGHT_VER+').');return;}
  // NUCLEAR OVERWRITE — replaces ALL cached freight with the hardcoded seed.
  // Use this when stale matrix-fed values or prior manual edits drift away from
  // current NM/routing assumptions and you want a clean baseline. The silent
  // auto-migrate on page load handles the "preserve edits" case separately.
  const msg='⚠ RESET FREIGHT TO SEED\n\n'
    +'This overwrites ALL freight curves with the hardcoded seed ('+CP_FREIGHT_VER+'):\n'
    +'• New routes to add: '+d.newKeys.length+'\n'
    +'• Routes that will be reset: '+d.changedKeys.length+'\n'
    +'• Total cells updated: '+d.cellDiffs+'\n\n'
    +'Your manual edits AND matrix-fed values will be replaced. To rebuild matrix-\n'
    +'based freight after this, go to Foundation → Freight Curves → UPDATE MATRIX.\n\n'
    +'Continue?';
  if(!confirm(msg))return;
  cpSet('cp_freight',JSON.parse(JSON.stringify(CP_SEED_FR)));
  cpSet('cp_freight_ver',CP_FREIGHT_VER);
  cpSet('cp_freight_snap',JSON.parse(JSON.stringify(CP_SEED_FR)));
  CP.freight=cpMergeFreight();renderCargo();
}
function cpPhysApplySeed(){
  const d=cpPhysSeedDiff();
  if(!d.hasDiff){alert('✓ Physical differentials already match seed.');return;}
  if(!confirm('Apply phys-diff seed updates?\n\n'+d.cellDiffs+' cells will be reset to seed ('+d.newKeys.length+' new / '+d.changedKeys.length+' changed terminals). Continue?'))return;
  cpSet('cp_phys',JSON.parse(JSON.stringify(CP_SEED_PHYS)));
  CP.phys=JSON.parse(JSON.stringify(CP_SEED_PHYS));renderCargo();
}
function cpPricesApplySeed(){
  const d=cpPricesSeedDiff();
  if(!d.hasDiff){alert('✓ Flat prices already match seed.');return;}
  if(!confirm('Apply flat-price seed updates?\n\n'+d.cellDiffs+' cells will be reset to seed ('+d.newKeys.length+' new / '+d.changedKeys.length+' changed indices). Continue?'))return;
  cpSet('cp_fp',JSON.parse(JSON.stringify(CP_SEED_PRICES)));
  CP.fp=JSON.parse(JSON.stringify(CP_SEED_PRICES));renderCargo();
}

// ── Auto-migration (3-way merge) ─────────────────────────────────────────────
// Silently migrate cells whose cached value still matches the *previously-applied*
// seed. Cells where cached ≠ prior seed are treated as explicit user edits and
// preserved. Runs on initCargo so new deploys flow through without RESET ALL.
function _autoMigrateSeed(seedMap,snapKey,cacheKey){
  const snap=cpGet(snapKey,null);
  const cached=cpGet(cacheKey,null);
  if(!snap){
    // First run of this feature — can't know prior seed. Adopt current seed as
    // baseline so subsequent seed changes can be auto-migrated.
    cpSet(snapKey,JSON.parse(JSON.stringify(seedMap)));
    return 0;
  }
  if(!cached||typeof cached!=='object'){cpSet(snapKey,JSON.parse(JSON.stringify(seedMap)));return 0;}
  let migrated=0;
  const out={...cached};
  Object.keys(seedMap).forEach(k=>{
    const sd=seedMap[k], sn=snap[k], cv=cached[k];
    if(!Array.isArray(sd))return;
    if(!Array.isArray(cv)){
      // Key added to seed since last snap — adopt wholesale (no user edits possible yet).
      out[k]=sd.slice();migrated+=sd.length;return;
    }
    const merged=cv.slice();
    sd.forEach((sNew,i)=>{
      const sOld=Array.isArray(sn)?sn[i]:undefined;
      const c=cv[i];
      if(sOld==null)return; // no prior baseline for this cell — don't touch user data
      const cMatchesOld=c!=null&&!isNaN(c)&&Math.abs(c-sOld)<1e-4;
      const seedChanged=sNew==null||sOld==null||Math.abs(sNew-sOld)>=1e-4;
      if(cMatchesOld&&seedChanged){merged[i]=sNew;migrated++;}
    });
    out[k]=merged;
  });
  if(migrated>0)cpSet(cacheKey,out);
  cpSet(snapKey,JSON.parse(JSON.stringify(seedMap)));
  return migrated;
}
function initCargo(){
  // Auto-migrate cells that still match the previously-applied seed. User edits
  // (cached ≠ prior seed) are preserved. Collect counts for a single status toast.
  const _migF=_autoMigrateSeed(CP_SEED_FR,     'cp_freight_snap','cp_freight');
  const _migH=_autoMigrateSeed(CP_SEED_PHYS,   'cp_phys_snap',   'cp_phys');
  const _migP=_autoMigrateSeed(CP_SEED_PRICES, 'cp_prices_snap', 'cp_fp');
  if(_migF+_migH+_migP>0){
    console.log('[LNG TradeOS] Auto-migrated seed updates — freight:'+_migF+' phys:'+_migH+' prices:'+_migP);
  }
  // Persist seeds on first load so seed-diff buttons show ✓ until user edits something.
  const _fp0=cpGet('cp_fp',null);
  CP.fp=_fp0||JSON.parse(JSON.stringify(CP_SEED_PRICES));
  if(!_fp0)cpSet('cp_fp',CP.fp);
  const _phys0=cpGet('cp_phys',null);
  CP.phys=_phys0||JSON.parse(JSON.stringify(CP_SEED_PHYS));
  // Backfill new CP.phys keys (france/germany/belgium) on old stored blobs
  ['france','germany','belgium'].forEach(k => {
    if(!Array.isArray(CP.phys[k]) || CP.phys[k].length !== 24){
      CP.phys[k] = [...CP_SEED_PHYS[k]];
    }
  });
  if(!_phys0)cpSet('cp_phys',CP.phys);
  const _fr0=cpGet('cp_freight',null);
  if(!_fr0||Object.keys(_fr0).length===0){
    cpSet('cp_freight',JSON.parse(JSON.stringify(CP_SEED_FR)));
    cpSet('cp_freight_ver',CP_FREIGHT_VER);
  }
  CP.freight=cpMergeFreight();
  CP.liqFee=cpGet('cp_liqfee',Array(24).fill(0));
  CP.histSnaps=cpGet('cp_hist_snaps',[]);
  CP.hhSlope=cpGet('cp_hh_slope',1.15);
  CP.globalArbIdx=cpGet('cp_global_arb_idx','TTF');
  CP.coghMode=cpGet('cp_cogh_mode',false);
  CP.tab=0;renderCargo();
}
function renderCargo(){
  const wrap=document.getElementById('cargo-wrap');if(!wrap)return;
  // Per-section seed status. Green ✓ = cache matches seed (click to confirm).
  // Amber ⚠ N = seed has N cell updates pending (click to apply).
  const prD=cpPricesSeedDiff(),frD=cpFreightSeedDiff(),phD=cpPhysSeedDiff();
  const seedBtn=(lbl,d,fn,tip)=>{
    const ok=!d.hasDiff;
    const bc=ok?'rgba(76,175,80,.4)':'rgba(255,183,77,.55)';
    const c=ok?'#81c784':'#ffb74d';
    const suf=ok?' ✓':' ⚠'+d.cellDiffs;
    return `<button class="f-btn sm" onclick="${fn}()" title="${tip}" style="border-color:${bc};color:${c}">${lbl}${suf}</button>`;
  };
  wrap.innerHTML=`
  <div style="background:#070b14;border-bottom:1px solid #1e3a5f;padding:8px 16px;display:flex;align-items:center;gap:8px;flex-wrap:wrap">
    <span style="color:#4fc3f7;font-weight:700;font-size:11px;letter-spacing:2px">LNG GLOBAL NETBACK MODEL</span>
    <span style="flex:1"></span>
    <span style="color:#3d5070;font-size:9px;letter-spacing:.08em">${CP_FREIGHT_VER}</span>
    ${seedBtn('PRICES SEED',prD,'cpPricesApplySeed','Flat prices vs seed. ✓ = identical. ⚠ = click to apply pending seed updates (prices changes frequently — use SYNC PRICES for live pulls).')}
    ${seedBtn('FREIGHT SEED',frD,'cpFreightApplySeed','Freight vs seed. Freight is typically refreshed weekly. ✓ = identical, no action needed. ⚠ = click to apply pending seed updates. Manual cell edits persist until you click apply.')}
    ${seedBtn('PHYS SEED',phD,'cpPhysApplySeed','Physical differentials vs seed. ✓ = identical. ⚠ = click to apply pending seed updates.')}
    <button class="f-btn sm" onclick="cpSyncPrices()" title="Pull latest JKM/TTF/HH from Financial Trading tab">↺ SYNC PRICES</button>
    <button class="f-btn sm" onclick="cpSyncFreight()" title="Pull latest freight $/MMBtu from validated freight matrix">↺ SYNC FREIGHT</button>
    <button class="f-btn sm" onclick="cpForceReset()" title="Wipe ALL localStorage cache and reinitialise from seed" style="border-color:rgba(255,82,82,.3);color:#ef5350">⚠ RESET ALL</button>
  </div>
  <div class="f-subnav">${CP_TABS.map((t,i)=>`<button class="f-tab${CP.tab===i?' active':''}" onclick="cpTab(${i})">${t}</button>`).join('')}</div>
  <div class="f-body" id="cp-body"></div>`;
  renderCargoTab();
}
function cpTab(i){CP.tab=i;if(i!==CP._lastTab)CP.selBasinOrg=null;CP._lastTab=i;document.querySelectorAll('#cargo-wrap .f-tab').forEach((t,j)=>t.classList.toggle('active',j===i));renderCargoTab();}
function renderCargoTab(){const b=document.getElementById('cp-body');if(!b)return;
  // Clamp selMonth to horizon cap so tabs never access out-of-range months after expiry roll
  const _vN=horizonIdx();if(CP.selMonth==null||CP.selMonth<0||CP.selMonth>=_vN)CP.selMonth=0;
  const d=cpDerived();
  if(CP.tab===0)b.innerHTML=cpPhysDiff(d);
  else if(CP.tab===1)b.innerHTML=cpDesPrices(d);
  else if(CP.tab===2)b.innerHTML=cpGlobalArb(d);
  else if(CP.tab===3)b.innerHTML=cpAtlanticArb(d);
  else if(CP.tab===4)b.innerHTML=cpMEIArb(d);
  else if(CP.tab===5)b.innerHTML=cpPacificArb(d);
  else if(CP.tab===6)b.innerHTML=cpFrDiffBasis(d);
}

// ── Sync functions ─────────────────────────────────────────────────────────
function cpSyncPrices(){
  if(!sDates||!sDates.length){alert('No price data loaded. Load via Financial Trading first.');return;}
  const latest=sDates[sDates.length-1];const row=aD[latest];if(!row){alert('No data for '+latest);return;}
  const mapIdx=pk=>{const found=ML.findIndex(m=>{const ms={Jan:'01',Feb:'02',Mar:'03',Apr:'04',May:'05',Jun:'06',Jul:'07',Aug:'08',Sep:'09',Oct:'10',Nov:'11',Dec:'12'};const p=m.split('-');return '20'+p[1]+'-'+ms[p[0]]===pk;});return found;};
  const keys=['HH','TTF','JKM','SP_JT'];
  const newFp={HH:[...CP.fp.HH],TTF:[...CP.fp.TTF],JKM:[...CP.fp.JKM],SP_JT:[...(CP.fp.SP_JT||new Array(24).fill(null))]};
  let count=0;
  if(aD&&sDates.length){
    sDates.forEach(date=>{const r=aD[date];if(!r||!r.rows)return;r.rows.forEach(row=>{const idx=mapIdx(row.pk);if(idx<0||idx>=24)return;keys.forEach(k=>{if(row[k]!=null){newFp[k][idx]=row[k];count++;}});});});
  }
  CP.fp=newFp;cpSet('cp_fp',newFp);renderCargoTab();
  alert('✓ Prices synced from Financial Trading ('+count+' data points updated).');
}
function cpSyncFreight(){
  if(!F.validatedMatrix){alert('No validated freight matrix. Go to Freight Calculator → ② Update The Curves → MATRIX → Validate & Freeze first.');return;}
  const vm=F.validatedMatrix;const newFr={...CP.freight};let count=0;
  // Iterate validated matrix entries and populate CP.freight
  // vm[supplyId][dischId][mi] = $/MMBtu
  const routeMap=[
    ['sabine','rotterdam','sabine_rotterdam'],['sabine','tokyo','sabine_tokyo'],['sabine','dahej','sabine_dahej'],['sabine','ainsukhna','sabine_ain'],
    ['angola','rotterdam','angola_gate'],['angola','tokyo','angola_tokyo'],['angola','dahej','angola_dahej'],['angola','ainsukhna','angola_ain'],['angola','maptaphut','angola_maptaphut'],
    ['nigeria','rotterdam','nigeria_gate'],['nigeria','tokyo','nigeria_tokyo'],['nigeria','dahej','nigeria_dahej'],['nigeria','ainsukhna','nigeria_ain'],['nigeria','maptaphut','nigeria_maptaphut'],
    ['trinidad','rotterdam','trinidad_gate'],['trinidad','tokyo','trinidad_tokyo'],['trinidad','dahej','trinidad_dahej'],['trinidad','ainsukhna','trinidad_ain'],
    ['qatar','rotterdam','qatar_gate'],['qatar','tokyo','qatar_tokyo'],['qatar','dahej','qatar_dahej'],['qatar','ainsukhna','qatar_ain'],
    ['oman','rotterdam','oman_gate'],['oman','tokyo','oman_tokyo'],['oman','dahej','oman_dahej'],['oman','ainsukhna','oman_ain'],
    ['sabine','swinoujscie','sabine_swinoujscie'],
    ['australia_b','tokyo','australia_b_tokyo'],['australia_b','ainsukhna','australia_b_ain'],
    ['australia_g','tokyo','australia_g_tokyo'],['australia_g','ainsukhna','australia_g_ain'],
    ['indonesia','tokyo','indonesia_tokyo'],['indonesia','ainsukhna','indonesia_ain'],
  ];
  routeMap.forEach(([orig,disch,key])=>{
    if(vm[orig]&&vm[orig][disch]){
      const arr=ML.map((_,mi)=>{const v=vm[orig][disch][mi];return v!=null?v:newFr[key]?.[mi]??null;});
      if(arr.some(v=>v!=null)){newFr[key]=arr;count++;}
    }
  });
  CP.freight=newFr;cpSet('cp_freight',newFr);cpSet('cp_freight_ver',CP_FREIGHT_VER);renderCargoTab();
  alert('✓ Freight synced from validated matrix ('+count+' routes updated).');
}

// ── Tab 0: Phys Differentials ───────────────────────────────────────────────
// Uses the global horizonIdx()/vML() helpers so the cap stays in sync with
// every other netback-consuming module and rolls forward on expiry.
