async function syncPublicState(){
  // Pull the admin-published state, overwrite matching localStorage keys, then
  // reload if anything changed. Skips if already synced with the current remote
  // timestamp (tracked per-browser in lngtradeos_public_state_ts).
  try{
    const res=await fetch(PUBLIC_STATE_URL+'?t='+Date.now(),{cache:'no-cache'});
    if(!res.ok)return false;
    const state=await res.json();
    const remoteTs=state?.__meta?.exportedAt||'';
    if(!remoteTs)return false;
    const localTs=localStorage.getItem('lngtradeos_public_state_ts')||'';
    if(localTs===remoteTs)return false;

    // Safari's ~5MB localStorage quota can be exhausted by other keys. A
    // silent setItem failure on lngTradeOS_v5 combined with writing the ts
    // flag anyway caused the "NO DATA LOADED" stuck state. If any key fails
    // (typically QuotaExceeded on the big ones), bail WITHOUT setting the ts
    // flag so the next load retries — and log loudly so the issue is visible.
    let applied=0;
    const failures=[];
    PUBLIC_STATE_KEYS.forEach(k=>{
      if(state[k]!=null){
        try{localStorage.setItem(k,state[k]);applied++;}
        catch(e){failures.push({k,err:e.name||e.message});}
      }
    });
    if(failures.length){
      console.error('[syncPublicState] setItem failed for '+failures.length+' key(s):',failures);
      console.error('[syncPublicState] Keeping ts flag unset so next load retries. Free localStorage space (Storage → Local Storage in DevTools) and reload.');
      return false;
    }
    localStorage.setItem('lngtradeos_public_state_ts',remoteTs);
    console.log('[LNG TradeOS] Synced '+applied+' keys from public_state.json (exported '+remoteTs+')');
    return true;
  }catch(e){return false;}
}
window.syncPublicState=syncPublicState;

// Auto-fetch EEX Gas Curves XLSX — runs independently of public_state.json so
// curves update whenever the scraper laptop pushes a new xlsx to the repo.
// Uses HEAD + Last-Modified to skip re-parse when the file hasn't changed.
const EEX_XLSX_URL='data/EEX_Gas_Curves.xlsx';

// Wait for the LNG EOD cache (aD / sDates) to be populated before EEX
// parsing runs — parseEEXFile needs aD for EUR/USD conversion via
// getEURUSD(). If aD is empty, the 1.09 hardcoded fallback kicks in and
// every EEX USD value gets cached with the wrong FX rate.
async function _waitForAD(timeoutMs=3000){
  const start=Date.now();
  while(Date.now()-start<timeoutMs){
    if(typeof sDates!=='undefined'&&sDates.length>0&&typeof aD!=='undefined'){
      // Also require at least one row with a valid EURUSD, else getEURUSD
      // will still return the 1.09 fallback.
      for(let i=sDates.length-1;i>=0;i--){
        const r=aD[sDates[i]]?.rows?.[0];
        if(r?.EURUSD>0.5)return true;
      }
    }
    await new Promise(r=>setTimeout(r,100));
  }
  return false;
}

async function syncEEX(){
  // Always re-fetch and re-parse on every page load. Bypasses all caching
  // to guarantee no stale data after user pushes a new XLSX. Extra ~500KB
  // per load is worth the reliability guarantee.
  console.log('[EEX] syncEEX start');
  try{
    const url=EEX_XLSX_URL+'?t='+Date.now();
    const res=await fetch(url,{cache:'no-store'});
    if(!res.ok){console.warn('[EEX] fetch failed:',res.status);return false;}
    const buf=await res.arrayBuffer();
    console.log('[EEX] XLSX downloaded:',buf.byteLength,'bytes');
    if(typeof XLSX==='undefined'){console.warn('[EEX] XLSX lib not loaded yet');return false;}
    if(typeof parseEEXFile!=='function'){console.warn('[EEX] parseEEXFile not defined yet');return false;}
    // Wait for aD to have real EURUSD data — otherwise conversions use the
    // 1.09 hardcoded fallback, which silently corrupts all USD values.
    const adReady=await _waitForAD(4000);
    console.log('[EEX] aD ready:',adReady,'sDates.length:',sDates.length);
    if(!adReady){
      console.error('[EEX] aD not populated after 4s — ABORTING parse (would use wrong EUR/USD). Try reloading.');
      return false;
    }
    // Wipe any stale cache before re-parsing so we don't merge with old data
    localStorage.removeItem('eex_v1');
    Object.keys(eexD).forEach(k=>delete eexD[k]);
    eexDates=[];
    const added=parseEEXFile(buf);
    const latest=eexDates[eexDates.length-1]||'n/a';
    console.log('[EEX] Parsed OK — '+eexDates.length+' dates, latest='+latest+', EUR/USD used='+getEURUSD(latest));
    return true;
  }catch(e){console.warn('[EEX] auto-fetch failed:',e.message);return false;}
}
window.syncEEX=syncEEX;

// One-time cache invalidation — bump this tag when EEX_HUBS or parsing logic
// changes so existing viewers force a fresh XLSX parse instead of trusting
// their stale localStorage (which was cached before the new hub was added).
(function invalidateStaleEEX(){
  try{
    const TAG='lngtradeos_eex_cache_tag';
    // Bump this tag whenever the EEX parser, EEX_HUBS list, or
    // PUBLIC_STATE_KEYS membership changes, so existing viewers force a
    // fresh XLSX fetch instead of trusting a stale localStorage cache.
    const EXPECTED='v6-merge-not-replace';
    if(localStorage.getItem(TAG)!==EXPECTED){
      localStorage.removeItem('eex_v1');
      localStorage.removeItem('lngtradeos_eex_xlsx_ts');
      // Also invalidate the public_state timestamp so any lingering stale
      // eex_v1 baked into an old public_state.json doesn't re-clobber.
      localStorage.removeItem('lngtradeos_public_state_ts');
      localStorage.setItem(TAG,EXPECTED);
    }
  }catch(e){}
})();

// Two-stage boot with independent session flags:
//   Stage 1 (pstate): syncPublicState. If the remote snapshot differs from
//     what's cached locally, reload so modules re-initialise aD from the
//     fresh lngTradeOS_v5 in localStorage. This ensures EUR/USD is real.
//   Stage 2 (eex): syncEEX. Runs AFTER aD is fresh so parseEEXFile's
//     EUR→USD conversion uses the real FX rate, not the 1.09 fallback.
//     Re-renders the dashboard tiles in-place without a full reload.
