  // YYYY.MM.DD or YYYY-MM-DD or YYYY_MM_DD  (new Drive format: "OB LNG EOD Curve 2024.03.15.xlsx")
  let m=name.match(/(\d{4})[._\s\-](\d{2})[._\s\-](\d{2})/);
  if(m){const d=new Date(+m[1],+m[2]-1,+m[3]);if(!isNaN(d)&&+m[1]>=2020&&+m[1]<=2040)return d;}
