// ── Unit conversion ──
function gaCV(val,fromDay=false){
  if(val==null||isNaN(val))return null;
  let mcm=fromDay?val*30:val;
  return guConvPipe(mcm);
}
function gaCVGWh(val){if(val==null)return null;return gaCV(val/10.55);}
