const IND_SECTOR_LBLS = {Power:'Power',CGD:'CGD',Fertilizer:'Fertilizer',Refinery:'Refinery',Petrochem:'Petrochem',LPGShrink:'LPG Shrink',SteelDRI:'Steel/DRI',PipelineIC:'Pipeline I/C',Other:'Other'};

// PPAC data hardcoded
